'use client';

import Link from 'next/link';
import { useMemo, useState } from 'react';
import SyncGmailInboxButton from '@/components/crm/SyncGmailInboxButton';
import type { LeadRecord, LeadStatus } from '@/lib/crm-types';
import { LEAD_STATUSES, LEAD_STATUS_LABELS } from '@/lib/crm-types';

const statusBadge: Record<LeadStatus, string> = {
  new_lead: 'bg-emerald-50 text-emerald-800 ring-emerald-600/20',
  warm_lead: 'bg-amber-50 text-amber-900 ring-amber-600/20',
  active_customer: 'bg-primary/10 text-primary-dark ring-primary/25',
  delinquent: 'bg-red-50 text-red-800 ring-red-600/15',
  inactive: 'bg-gray-100 text-gray-600 ring-gray-500/10',
};

export default function CrmLeadsTable({ initialLeads }: { initialLeads: LeadRecord[] }) {
  const [q, setQ] = useState('');
  const [status, setStatus] = useState<LeadStatus | ''>('');

  const filtered = useMemo(() => {
    let rows = initialLeads;
    if (status) rows = rows.filter((l) => l.status === status);
    const t = q.trim().toLowerCase();
    if (t) {
      rows = rows.filter(
        (l) =>
          l.name.toLowerCase().includes(t) ||
          l.email.includes(t) ||
          l.phone.includes(t) ||
          l.physicalAddress.toLowerCase().includes(t)
      );
    }
    return rows;
  }, [initialLeads, q, status]);

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row sm:items-end gap-4 justify-between">
        <div>
          <h1 className="text-2xl font-bold text-gray-900 tracking-tight">Leads</h1>
          <p className="text-gray-500 text-sm mt-1">
            Customer replies arrive in Gmail—use <strong>Sync Gmail replies</strong> to pull them into timelines here.
          </p>
        </div>
        <div className="flex flex-col sm:flex-row gap-2 sm:items-center">
          <SyncGmailInboxButton />
          <Link
            href="/crm/leads/new"
            className="inline-flex justify-center items-center px-4 py-2.5 rounded-lg bg-primary text-white text-sm font-semibold hover:bg-primary-dark transition-colors shadow-sm"
          >
            Add lead
          </Link>
        </div>
      </div>

      <div className="flex flex-col sm:flex-row gap-3">
        <input
          type="search"
          placeholder="Search name, email, phone, address…"
          value={q}
          onChange={(e) => setQ(e.target.value)}
          className="flex-1 px-4 py-2.5 rounded-lg border border-gray-200 text-sm focus:outline-none focus:ring-2 focus:ring-primary/25 focus:border-primary"
        />
        <select
          value={status}
          onChange={(e) => setStatus((e.target.value as LeadStatus | '') || '')}
          className="px-4 py-2.5 rounded-lg border border-gray-200 text-sm bg-white focus:outline-none focus:ring-2 focus:ring-primary/25 focus:border-primary min-w-[11rem]"
        >
          <option value="">All statuses</option>
          {LEAD_STATUSES.map((s) => (
            <option key={s} value={s}>
              {LEAD_STATUS_LABELS[s]}
            </option>
          ))}
        </select>
      </div>

      <div className="bg-white rounded-xl border border-gray-200 shadow-sm overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-sm text-left">
            <thead className="bg-gray-50/80 text-gray-600 font-medium border-b border-gray-200">
              <tr>
                <th className="px-4 py-3">Name</th>
                <th className="px-4 py-3">Email</th>
                <th className="px-4 py-3 hidden md:table-cell">Phone</th>
                <th className="px-4 py-3">Status</th>
                <th className="px-4 py-3 hidden lg:table-cell">Updated</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100">
              {filtered.length === 0 ? (
                <tr>
                  <td colSpan={5} className="px-4 py-12 text-center text-gray-500">
                    No leads match. Add one or adjust filters.
                  </td>
                </tr>
              ) : (
                filtered.map((lead) => (
                  <tr key={lead.id} className="hover:bg-gray-50/80 transition-colors">
                    <td className="px-4 py-3">
                      <Link
                        href={`/crm/leads/${lead.id}`}
                        className="font-medium text-gray-900 hover:text-primary"
                      >
                        {lead.name}
                      </Link>
                    </td>
                    <td className="px-4 py-3 text-gray-600">{lead.email}</td>
                    <td className="px-4 py-3 text-gray-600 hidden md:table-cell">
                      {lead.phone || '—'}
                    </td>
                    <td className="px-4 py-3">
                      <span
                        className={`inline-flex items-center rounded-md px-2 py-0.5 text-xs font-medium ring-1 ring-inset ${statusBadge[lead.status]}`}
                      >
                        {LEAD_STATUS_LABELS[lead.status]}
                      </span>
                    </td>
                    <td className="px-4 py-3 text-gray-500 hidden lg:table-cell whitespace-nowrap">
                      {new Date(lead.updatedAt).toLocaleDateString(undefined, {
                        month: 'short',
                        day: 'numeric',
                        year: 'numeric',
                      })}
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}
